const G = `
@import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Sans:wght@400;500;600;700&family=Barlow+Condensed:wght@500;700;900&display=swap');
*{margin:0;padding:0;box-sizing:border-box;-webkit-tap-highlight-color:transparent;}
input,button,select,textarea{font-family:inherit;touch-action:manipulation;}
button{min-height:44px;}
h1,h2,h3{text-shadow:0 1px 4px rgba(0,0,0,0.8),0 0 20px rgba(0,0,0,0.5);}
.bebas{text-shadow:0 2px 6px rgba(0,0,0,0.9),0 0 30px rgba(0,0,0,0.6);}
body{-webkit-text-size-adjust:100%;overflow-x:hidden;}
@keyframes bounce{0%,100%{transform:translateY(0)}50%{transform:translateY(-8px)}}
@media(max-width:600px){
  .hide-mobile{display:none!important;}
  h1{font-size:clamp(2.2rem,8vw,5rem)!important;}
  .card-grid{grid-template-columns:1fr!important;}
}
:root{
  --g:#1DB954;--g2:#17a347;--gold:#F5C542;
  --dark:#0B0F0E;--d2:#111815;--d3:#161d1b;--d4:#1e2724;
  --text:#f0f5f3;--muted:#92a89f;--border:rgba(29,185,84,0.15);
  --text-dim:rgba(240,245,243,0.7);--text-faint:rgba(240,245,243,0.45);
}
html{scroll-behavior:smooth;}
body{background:var(--dark);color:var(--text);-webkit-font-smoothing:antialiased;-moz-osx-font-smoothing:grayscale;text-rendering:optimizeLegibility;font-family:'DM Sans',sans-serif;overflow-x:hidden;}
::-webkit-scrollbar{width:4px;}
::-webkit-scrollbar-track{background:var(--d2);}
::-webkit-scrollbar-thumb{background:var(--g);border-radius:4px;}
@keyframes fadeUp{from{opacity:0;transform:translateY(18px)}to{opacity:1;transform:translateY(0)}}
@keyframes pulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.4;transform:scale(1.6)}}
@keyframes spin{to{transform:rotate(360deg)}}
@keyframes popIn{from{opacity:0;transform:scale(.93) translateY(10px)}to{opacity:1;transform:scale(1) translateY(0)}}
@keyframes ticker{from{transform:translateX(0)}to{transform:translateX(-50%)}}
.protected-content { -webkit-touch-callout: none; -webkit-user-select: none; user-select: none; }
.screenshot-shield { position:fixed; inset:0; background:#000; z-index:99999; display:none; pointer-events:none; }
body.screenshot-active .screenshot-shield { display:block !important; }
@media print { .protected-content, .ticket-img { filter: blur(20px) !important; } }
`;


// -- Time utilities ------------------------------------------------------------
// Parse match time string into a Date object for comparison
// Format examples: "Hoy · 6:30 PM PDT", "Lun 27 · 5:00 PM PDT", "Mar 28 Abr · 4:00 PM PDT"
function parseMatchTime(timeStr) {
  if (!timeStr) return null;
  try {
    const now = new Date();
    const str = timeStr.toLowerCase();

    // Extract time portion HH:MM AM/PM
    const timeMatch = str.match(/(\d{1,2}):(\d{2})\s*(am|pm)/i);
    if (!timeMatch) return null;
    let hours = parseInt(timeMatch[1]);
    const mins = parseInt(timeMatch[2]);
    const ampm = timeMatch[3].toLowerCase();
    if (ampm === "pm" && hours !== 12) hours += 12;
    if (ampm === "am" && hours === 12) hours = 0;

    // Extract day
    let day = now.getDate();
    let month = now.getMonth();
    let year = now.getFullYear();

    const dayMap = { lun:1, mar:2, mié:3, mie:3, jue:4, vie:5, sáb:6, sab:6, dom:0 };
    const monthMap = { ene:0, feb:1, mar:2, abr:3, may:4, jun:5, jul:6, ago:7, sep:8, oct:9, nov:10, dic:11 };

    // Check for month name (e.g. "28 abr")
    const dateMatch = str.match(/(\d{1,2})\s*(ene|feb|mar|abr|may|jun|jul|ago|sep|oct|nov|dic)/i);
    if (dateMatch) {
      day = parseInt(dateMatch[1]);
      month = monthMap[dateMatch[2].toLowerCase()];
    } else if (str.includes("hoy")) {
      day = now.getDate();
      month = now.getMonth();
    } else {
      // Day of week - find next occurrence
      for (const [name, dow] of Object.entries(dayMap)) {
        if (str.startsWith(name)) {
          const target = dow;
          let diff = (target - now.getDay() + 7) % 7;
          if (diff === 0) diff = 7;
          const d = new Date(now);
          d.setDate(now.getDate() + diff);
          day = d.getDate();
          month = d.getMonth();
          break;
        }
      }
    }

    // Build date - assume CDT/PDT = UTC-6 offset approx, convert to local
    const matchDate = new Date(year, month, day, hours, mins, 0);
    return matchDate;
  } catch { return null; }
}

function isMatchStarted(timeStr) {
  const matchDate = parseMatchTime(timeStr);
  if (!matchDate) return false;
  return new Date() >= matchDate;
}

function minutesUntilMatch(timeStr) {
  const matchDate = parseMatchTime(timeStr);
  if (!matchDate) return 999;
  return Math.floor((matchDate - new Date()) / 60000);
}

function CountdownBadge({ timeStr }) {
  // No hooks - pure calculation to avoid React #310
  const mins = minutesUntilMatch(timeStr);
  if (mins <= 0) return (
    <span style={{background:"#f44336",color:"#fff",fontSize:"0.6rem",fontWeight:900,padding:"2px 7px",borderRadius:100,letterSpacing:1}}>EN VIVO</span>
  );
  if (mins < 60) return (
    <span style={{background:"rgba(245,197,66,0.2)",color:"#F5C542",fontSize:"0.6rem",fontWeight:900,padding:"2px 7px",borderRadius:100,letterSpacing:1}}>⏱ {mins}min</span>
  );
  if (mins < 1440) return (
    <span style={{background:"rgba(29,185,84,0.12)",color:"var(--g)",fontSize:"0.6rem",fontWeight:700,padding:"2px 7px",borderRadius:100,letterSpacing:1}}>🕐 {Math.floor(mins/60)}h {mins%60}m</span>
  );
  return null;
}


