      "yankees":     [{home:"Texas Rangers",away:"New York Yankees",league:"MLB",time:"Lun 27 Abr - 5:05 PM ET",venue:"Globe Life Field"},{home:"New York Yankees",away:"TBD",league:"MLB",time:"Mar 28 Abr - TBD",venue:"Yankee Stadium"}],
