      "cubs":        [{home:"San Diego Padres",away:"Chicago Cubs",league:"MLB",time:"Lun 27 Abr - 6:40 PM ET",venue:"Petco Park"}],
      "red sox":     [{home:"Toronto Blue Jays",away:"Boston Red Sox",league:"MLB",time:"Lun 27 Abr - 4:07 PM ET",venue:"Rogers Centre"}],
