// ── AUTH VIEW ─────────────────────────────────────────────────────────────────
function AuthView({ setView, setUser, mode }) {
  const [authMode, setAuthMode] = useState(mode || "login");
  const [form, setForm] = useState({ name:"", username:"", email:"", password:"", confirmPassword:"", paypal:"" });
  const [avatar, setAvatar] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const update = (k,v) => setForm(p=>({...p,[k]:v}));

  function handleAvatarChange(e) {
    const f = e.target.files[0];
    if (!f) return;
    const r = new FileReader();
    r.onload = ev => setAvatar(ev.target.result);
    r.readAsDataURL(f);
  }

  async function handleSubmit() {
    setError(""); setSuccess(""); setLoading(true);

    if (authMode === "login") {
      if (!form.email || !form.password) { setError("Ingresa tu correo y contraseña"); setLoading(false); return; }
      // Simulate login - in production calls /api/auth/login
      setTimeout(() => {
        const mockUser = {
          id: Date.now(),
          name: form.email.split("@")[0],
          username: form.email.split("@")[0],
          email: form.email,
          role: form.email.includes("admin") ? "admin" : form.email.includes("pro") ? "pro" : "basic",
          roi: "+0%",
          balance: 0,
          avatar: null,
        };
        setUser(mockUser);
        setView("home");
        setLoading(false);
      }, 1000);
    }

    else if (authMode === "register") {
      if (!form.name || !form.username || !form.email || !form.password)
        { setError("Todos los campos son requeridos"); setLoading(false); return; }
      if (form.password !== form.confirmPassword)
        { setError("Las contraseñas no coinciden"); setLoading(false); return; }
      if (form.password.length < 6)
        { setError("La contraseña debe tener al menos 6 caracteres"); setLoading(false); return; }

      setTimeout(() => {
        const newUser = {
          id: Date.now(),
          name: form.name,
          username: form.username,
          email: form.email,
          role: "basic",
          roi: "+0%",
          balance: 0,
          paypal: form.paypal,
          avatar: avatar || null,
        };
        setUser(newUser);
        setView("home");
        setLoading(false);
      }, 1200);
    }

    else if (authMode === "reset") {
      if (!form.email) { setError("Ingresa tu correo"); setLoading(false); return; }
      setTimeout(() => {
        setSuccess("Te enviamos un enlace para restablecer tu contraseña");
        setLoading(false);
      }, 1000);
    }
  }

  const inputStyle = {
    width:"100%", background:"var(--d4)", border:"1px solid var(--border)",
    borderRadius:8, padding:"13px 14px", color:"var(--text)", fontSize:"16px",
    outline:"none", marginBottom:12, boxSizing:"border-box", WebkitAppearance:"none",
  };

  const titles = { login:"Iniciar Sesión", register:"Crear Cuenta", reset:"Restablecer Contraseña" };

  return (
    <div style={{paddingTop:80,minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:"clamp(80px,12vw,100px) 5% 60px",background:"var(--dark)"}}>
      <div style={{width:"100%",maxWidth:420,animation:"popIn .4s ease"}}>

        {/* Logo */}
        <div style={{textAlign:"center",marginBottom:32}}>
          <img src={LOGO_HERO} alt="ThePickZone" style={{height:80,width:"auto",marginBottom:12}}/>
          <h2 style={{fontFamily:"'Bebas Neue'",fontSize:"2rem",letterSpacing:1,color:"var(--text)"}}>{titles[authMode]}</h2>
        </div>

        {/* Card */}
        <div style={{background:"var(--d2)",border:"1px solid var(--border)",borderRadius:16,padding:28,boxShadow:"0 20px 60px rgba(0,0,0,0.4)"}}>

          {error && <div style={{background:"rgba(244,67,54,0.15)",border:"1px solid rgba(244,67,54,0.4)",borderRadius:8,padding:"10px 14px",marginBottom:16,fontSize:"0.82rem",color:"#f44336"}}>{error}</div>}
          {success && <div style={{background:"rgba(29,185,84,0.15)",border:"1px solid rgba(29,185,84,0.4)",borderRadius:8,padding:"10px 14px",marginBottom:16,fontSize:"0.82rem",color:"var(--g)"}}>{success}</div>}

          {/* REGISTER FIELDS */}
          {authMode === "register" && (
            <>
              {/* Avatar upload */}
              <div style={{textAlign:"center",marginBottom:20}}>
                <label style={{cursor:"pointer",display:"inline-block"}}>
                  <input type="file" accept="image/*" style={{display:"none"}} onChange={handleAvatarChange}/>
                  <div style={{width:80,height:80,borderRadius:"50%",background:"var(--d4)",border:`2px dashed ${avatar?"var(--g)":"var(--border)"}`,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 8px",overflow:"hidden",position:"relative"}}>
                    {avatar
                      ? <img src={avatar} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                      : <span style={{fontSize:"1.8rem"}}>📷</span>
                    }
                  </div>
                  <div style={{fontSize:"0.72rem",color:"var(--muted)"}}>Toca para subir foto de perfil</div>
                </label>
              </div>

              <input type="text" placeholder="Nombre completo" value={form.name} onChange={e=>update("name",e.target.value)} style={inputStyle}/>
              <input type="text" placeholder="Nombre de usuario" value={form.username} onChange={e=>update("username",e.target.value.toLowerCase().replace(/\s/g,""))} style={inputStyle}/>
              <input type="email" placeholder="Correo electrónico" value={form.email} onChange={e=>update("email",e.target.value)} style={inputStyle}/>
              <input type="password" placeholder="Contraseña (mín. 6 caracteres)" value={form.password} onChange={e=>update("password",e.target.value)} style={inputStyle}/>
              <input type="password" placeholder="Confirmar contraseña" value={form.confirmPassword} onChange={e=>update("confirmPassword",e.target.value)} style={inputStyle}/>

              {/* PayPal link */}
              <div style={{background:"var(--d4)",borderRadius:8,padding:"12px 14px",marginBottom:12,border:"1px solid var(--border)"}}>
                <div style={{fontSize:"0.72rem",color:"var(--muted)",marginBottom:6}}>💳 Link de PayPal para recibir pagos (opcional)</div>
                <input type="text" placeholder="tucorreo@paypal.com" value={form.paypal} onChange={e=>update("paypal",e.target.value)}
                  style={{width:"100%",background:"none",border:"none",outline:"none",color:"var(--text)",fontSize:"0.88rem",boxSizing:"border-box"}}/>
              </div>
            </>
          )}

          {/* LOGIN FIELDS */}
          {authMode === "login" && (
            <>
              <input type="email" placeholder="Correo electrónico" value={form.email} onChange={e=>update("email",e.target.value)} style={inputStyle}/>
              <input type="password" placeholder="Contraseña" value={form.password} onChange={e=>update("password",e.target.value)} style={inputStyle}/>
              <div style={{textAlign:"right",marginTop:-8,marginBottom:16}}>
                <button onClick={()=>setAuthMode("reset")} style={{background:"none",border:"none",color:"var(--g)",fontSize:"0.78rem",cursor:"pointer"}}>
                  ¿Olvidaste tu contraseña?
                </button>
              </div>
            </>
          )}

          {/* RESET FIELDS */}
          {authMode === "reset" && (
            <>
              <p style={{fontSize:"0.85rem",color:"var(--muted)",marginBottom:16,lineHeight:1.6}}>
                Ingresa tu correo y te enviaremos un enlace para restablecer tu contraseña.
              </p>
              <input type="email" placeholder="Correo electrónico" value={form.email} onChange={e=>update("email",e.target.value)} style={inputStyle}/>
            </>
          )}

          {/* Submit button */}
          <button onClick={handleSubmit} disabled={loading}
            style={{width:"100%",background:loading?"var(--d4)":"var(--g)",color:loading?"var(--muted)":"#000",border:"none",padding:"14px",borderRadius:8,fontFamily:"'Barlow Condensed'",fontSize:"1.1rem",fontWeight:900,letterSpacing:2,cursor:loading?"not-allowed":"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:10,marginBottom:16}}>
            {loading
              ? <><span style={{width:16,height:16,border:"2px solid var(--g)",borderTopColor:"transparent",borderRadius:"50%",animation:"spin 1s linear infinite",display:"inline-block"}}/>CARGANDO...</>
              : authMode==="login" ? "INICIAR SESIÓN" : authMode==="register" ? "CREAR CUENTA" : "ENVIAR ENLACE"
            }
          </button>

          {/* Switch mode links */}
          <div style={{textAlign:"center",fontSize:"0.82rem",color:"var(--muted)"}}>
            {authMode==="login" && (
              <>¿No tienes cuenta? <button onClick={()=>setAuthMode("register")} style={{background:"none",border:"none",color:"var(--g)",cursor:"pointer",fontWeight:700}}>Regístrate gratis</button></>
            )}
            {authMode==="register" && (
              <>¿Ya tienes cuenta? <button onClick={()=>setAuthMode("login")} style={{background:"none",border:"none",color:"var(--g)",cursor:"pointer",fontWeight:700}}>Inicia sesión</button></>
            )}
            {authMode==="reset" && (
              <button onClick={()=>setAuthMode("login")} style={{background:"none",border:"none",color:"var(--g)",cursor:"pointer",fontWeight:700}}>← Volver al login</button>
            )}
          </div>
        </div>

        {/* Back button */}
        <button onClick={()=>setView("home")} style={{background:"none",border:"none",color:"var(--muted)",fontSize:"0.8rem",cursor:"pointer",marginTop:16,display:"block",textAlign:"center",width:"100%"}}>
          ← Volver al inicio
        </button>
      </div>
    </div>
  );
}


// ── App root ──────────────────────────────────────────────────────────────────
export default function App() {
  const [view,setView] = useState("home");
  const [loading,setLoading] = useState(true);

  useEffect(()=>{
    const t = setTimeout(()=>setLoading(false), 1800);
    return ()=>clearTimeout(t);
  },[]);
  const [user,setUser] = useState(null);
  const [purchaseTarget,setPurchaseTarget] = useState(null);
  const [picks,setPicks] = useState(INITIAL_PICKS);
  const [selectedTipster, setSelectedTipster] = useState(null);
  const [notifications, setNotifications] = useState([
    { id:1, type:"new_pick",     title:"🔥 Nuevo pick de ManuPicks",          body:"Champions League - PSG vs Bayern · Momio 2.30",    time:"Hace 5 min",  read:false },
    { id:2, type:"result_won",   title:"✅ Pick ganado - Over 3 goles",        body:"Cagliari 3-2 Atalanta · Serie A · Confirmado",      time:"Hace 1 hora", read:false },
    { id:3, type:"result_lost",  title:"❌ Pick perdido - Over 3 tarjetas",    body:"Cagliari vs Atalanta · 0 tarjetas en el partido",   time:"Hace 1 hora", read:true  },
    { id:4, type:"payout",       title:"💰 Pago aprobado - $245.00",           body:"Semana 17 · Tu saldo ha sido transferido a PayPal", time:"Hace 2 horas",read:true  },
    { id:5, type:"new_pick",     title:"🔥 Nuevo pick de BetKing",             body:"NBA Playoffs - Celtics vs 76ers · Free pick",       time:"Hace 3 horas",read:true  },
  ]);
  const [picksLoaded,setPicksLoaded] = useState(false);

  // Load picks from persistent storage on mount
  useEffect(()=>{
    async function load(){
      try {
        const r = await window.storage.get("tpz_picks");
        if(r && r.value){
          const saved = JSON.parse(r.value);
          if(Array.isArray(saved) && saved.length >= INITIAL_PICKS.length){
            setPicks(saved);
          }
        }
      } catch(e){}
      setPicksLoaded(true);
    }
    load();
  },[]);

  // Save picks whenever they change
  useEffect(()=>{
    if(!picksLoaded) return;
    try { window.storage.set("tpz_picks", JSON.stringify(picks)); } catch(e){}
  },[picks, picksLoaded]);

  // Store user globally for purchase gate
  useEffect(()=>{ window._tpzUser = user; }, [user]);

  const gotoView = v=>{ setView(v); window.scrollTo({top:0,behavior:"smooth"}); };
  const addPick = p => {
    setPicks(prev => [p, ...prev]);
    // Notify all users
    const newNotif = {
      id: Date.now(),
      type: "new_pick",
      title: "🔥 Nuevo pick de " + (p.tipster||"Tipster"),
      body: p.league + " · " + p.match + (p.price > 0 ? " · $"+p.price : " · Free"),
      time: "Ahora mismo",
      read: false,
      pick: p,
    };
    setNotifications(prev => [newNotif, ...prev.slice(0,19)]);
  };

  useEffect(()=>{
    const shield=()=>{document.body.classList.add("screenshot-active");setTimeout(()=>document.body.classList.remove("screenshot-active"),2000);};
    const onBlur=()=>shield();
    const onVis=()=>{if(document.visibilityState==="hidden")shield();};
    const onKey=e=>{if(e.key==="PrintScreen"||(e.ctrlKey&&e.shiftKey&&(e.key==="S"||e.key==="4"||e.key==="3"))){e.preventDefault();shield();}};
    window.addEventListener("blur",onBlur);
    document.addEventListener("visibilitychange",onVis);
    document.addEventListener("keydown",onKey);
    return()=>{window.removeEventListener("blur",onBlur);document.removeEventListener("visibilitychange",onVis);document.removeEventListener("keydown",onKey);};
  },[]);

  return (
    <>
      <style>{G}</style>
      <div className="screenshot-shield"/>
      <NavBar view={view} setView={gotoView} user={user} setUser={setUser} notifications={notifications} setNotifications={setNotifications} setPurchaseTarget={setPurchaseTarget}/>
      {view==="home"        && <HomeView        setView={gotoView} setPurchaseTarget={setPurchaseTarget} picks={picks} setSelectedTipster={setSelectedTipster}/>}
      {view==="marketplace" && <MarketplaceView setView={gotoView} setPurchaseTarget={setPurchaseTarget} picks={picks}/>}
      {view==="purchase"    && <PurchaseView    pick={purchaseTarget} setView={gotoView}/>}
      {view==="pro-panel"   && <ProPanelView    user={user} addPick={addPick} setView={gotoView}/>}
      {view==="login"       && <AuthView        setView={gotoView} setUser={setUser} mode="login"/>}
      {view==="register"    && <AuthView        setView={gotoView} setUser={setUser} mode="register"/>}
      {view==="reset"       && <AuthView        setView={gotoView} setUser={setUser} mode="reset"/>}
      {view==="profile"     && <ProfileView     setView={gotoView} user={user} setUser={setUser}/>}
      {view==="become-pro"  && <BecomeProView   setView={gotoView} user={user} setUser={setUser}/>}
      {view==="pro-profile" && <ProProfileView  setView={gotoView} user={user} setUser={setUser} picks={picks}/>}
      {view==="search"      && <SearchView      setView={gotoView} setPurchaseTarget={setPurchaseTarget} picks={picks}/>}
      {view==="rankings"    && <RankingsView    setView={gotoView} picks={picks} setSelectedTipster={setSelectedTipster}/>}
      {view==="how-it-works" && <HowItWorksView  setView={gotoView}/>}
      {view==="terms"       && <TermsView       setView={gotoView}/>}
      {view==="privacy"     && <PrivacyView     setView={gotoView}/>}
      {view==="support"     && <SupportView     setView={gotoView} user={user}/>}
      {view==="tipster"     && <TipsterProfile  setView={gotoView} setPurchaseTarget={setPurchaseTarget} tipsterName={selectedTipster} picks={picks}/>}
      {!['home','marketplace','purchase','pro-panel','login','register','reset','profile','become-pro','pro-profile','admin-panel','admin-profile','revenue-dashboard','results','search','rankings','how-it-works','terms','privacy','support','tipster'].includes(view) && <NotFoundView setView={gotoView}/>}
      {view==="admin-panel"   && <AdminPanel       setView={gotoView} user={user} picks={picks}/>}
      {view==="admin-profile"   && <AdminProfileView  setView={gotoView} user={user} setUser={setUser}/>}
      {view==="revenue-dashboard" && <RevenueDashboard setView={gotoView} picks={picks}/>}
      <footer style={{background:"var(--dark)",borderTop:"1px solid var(--border)",padding:"40px 5%",display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:20}}>
        <img src={LOGO_NAVBAR} alt="ThePickZone" style={{height:36,width:"auto",opacity:.9}}/>
        <div style={{display:"flex",gap:20}}>{["Terminos","Privacidad","Soporte","Telegram"].map(l=><a key={l} href="#" style={{color:"var(--muted)",fontSize:"0.8rem",textDecoration:"none"}}>{l}</a>)}</div>
        <span style={{fontSize:"0.75rem",color:"var(--muted)"}}>2026 The Pick Zone.</span>
      </footer>
    </>
  );
}
